local http = require "resty.http"
local ngx = require "ngx"

-- Create an HTTP client object
local httpc = http.new()

-- Set the timeout for the HTTP request
httpc:set_timeout(1000) -- 1 second

-- Proxy the incoming request to the target URL
function proxy_request()
    local url = ngx.var.arg_url
    if not url then
        ngx.log(ngx.ERR, "No target URL provided")
        return ngx.exit(400)
    end

    -- Fetch the content from the target URL
    local res, err = httpc:request_uri(url)
    if not res then
        ngx.log(ngx.ERR, "Failed to fetch content from target URL: ", url)
        return ngx.exit(502)
    end

    -- Set the response headers and body
    ngx.header["Content-Type"] = res.headers["Content-Type"]
    ngx.status = res.status
    ngx.say(res.body)
end